/**
 * AI API Service
 * Provides AI streaming capabilities using user configuration or environment variables
 */

import { getAiRequestConfig } from "@/ai/config/useAiConfig";

// AI Callback interface used by the extensions
export interface AiStreamCallback {
  onStart?: () => void;
  onMessage?: (message: { content: string }) => void;
  onStop?: () => void;
  onError?: (error: Error) => void;
  /** 传入后可用 AbortController.abort() 或 signal.abort() 取消流式请求 */
  signal?: AbortSignal;
}

export interface AiApiResponse {
  success: boolean;
  content?: string;
  error?: string;
}

/** 统一错误对象，便于 UI 与扩展展示 */
export function normalizeAiError(error: unknown): Error {
  if (error instanceof Error) return error;
  if (typeof error === "string") return new Error(error);
  return new Error("AI 请求失败");
}

/**
 * Load API configuration
 * Priority: User config > Environment variables > Defaults
 */
function getAiConfig() {
  // First check user config (localStorage)
  const userConfig = getAiRequestConfig();
  if (userConfig) {
    return {
      provider: userConfig.provider,
      apiKey: userConfig.apiKey,
      baseUrl: userConfig.endpoint,
      model: userConfig.model,
      timeout: userConfig.timeout,
    };
  }

  // Fall back to environment variables
  const env = import.meta.env || {};
  return {
    provider: env.VITE_AI_PROVIDER || "openai",
    apiKey: env.VITE_AI_API_KEY || "",
    baseUrl: env.VITE_AI_BASE_URL || "",
    model: env.VITE_AI_MODEL || "gpt-4o-mini",
    timeout: DEFAULT_TIMEOUT,
  };
}

// Get base URL for provider
function getBaseUrl(provider: string, customUrl: string): string {
  if (customUrl) return customUrl;
  const urls: Record<string, string> = {
    openai: "https://api.openai.com/v1",
    aliyun: "https://dashscope.aliyuncs.com/compatible-mode/v1",
    deepseek: "https://api.deepseek.com/v1",
    ollama: "http://localhost:11434/api",
  };
  return urls[provider] || urls.openai;
}

// Default timeout for AI requests (60 seconds)
const DEFAULT_TIMEOUT = 60000;

/**
 * Simulate AI streaming response for demo purposes
 * Shows how the AI feature works without requiring API key configuration
 */
async function simulateAiStream(
  callback: AiStreamCallback,
  demoType: "continue" | "polish" | "summarize" | "translate" | "custom",
): Promise<void> {
  const demoMessages: Record<typeof demoType, string> = {
    continue:
      "这是 AI 续写功能的演示效果。\n\n💡 提示：要使用真实的 AI 功能，请在工具栏的 AI 设置中配置您的 API Key。\n\n支持的 AI 提供商：\n• OpenAI (GPT-4, GPT-3.5)\n• 阿里云通义千问\n• DeepSeek\n• Ollama (本地部署)\n\n配置后，AI 将根据您的内容智能续写，帮助您快速完成文档创作。",
    polish:
      "这是 AI 润色功能的演示效果。\n\n💡 提示：要使用真实的 AI 润色功能，请在工具栏的 AI 设置中配置您的 API Key。\n\n配置后，AI 将帮助您：\n• 优化文字表达，使语句更流畅\n• 修正语法错误\n• 提升专业度和可读性\n• 保持原意的同时改善文风",
    summarize:
      "这是 AI 总结功能的演示效果。\n\n💡 提示：要使用真实的 AI 总结功能，请在工具栏的 AI 设置中配置您的 API Key。\n\n配置后，AI 将智能提取内容要点，生成简洁的摘要，帮助读者快速理解核心信息。",
    translate:
      "这是 AI 翻译功能的演示效果。\n\n💡 Tip: To use the real AI translation feature, please configure your API Key in the AI Settings on the toolbar.\n\nAfter configuration, AI will provide high-quality translations while maintaining the original meaning and style.",
    custom:
      "这是自定义 AI 命令的演示效果。\n\n💡 提示：要使用真实的自定义 AI 功能，请在工具栏的 AI 设置中配置您的 API Key。\n\n配置后，您可以输入任何自定义指令，AI 将根据您的要求处理选中的文本。",
  };

  const message = demoMessages[demoType];
  const signal = callback.signal;

  if (signal?.aborted) {
    callback.onStop?.();
    return;
  }

  try {
    callback.onStart?.();

    let index = 0;
    const streamInterval = setInterval(() => {
      if (signal?.aborted) {
        clearInterval(streamInterval);
        callback.onStop?.();
        return;
      }
      if (index < message.length) {
        const chunkSize = Math.floor(Math.random() * 4) + 2;
        const chunk = message.slice(index, index + chunkSize);
        callback.onMessage?.({ content: chunk });
        index += chunkSize;
      } else {
        clearInterval(streamInterval);
        callback.onStop?.();
      }
    }, 50);

    const onExternalAbort = () => {
      clearInterval(streamInterval);
      callback.onStop?.();
    };
    signal?.addEventListener("abort", onExternalAbort, { once: true });
  } catch (error) {
    callback.onError?.(normalizeAiError(error));
  }
}

/**
 * Send streaming request to AI provider with timeout control
 */
async function sendStreamingRequest(
  prompt: string,
  content: string,
  callback: AiStreamCallback,
  demoType?: "continue" | "polish" | "summarize" | "translate" | "custom",
): Promise<void> {
  const config = getAiConfig();

  // If no API key configured, show demo/simulation instead of error
  if (!config.apiKey) {
    await simulateAiStream(callback, demoType || "custom");
    return;
  }

  if (callback.signal?.aborted) {
    callback.onStop?.();
    return;
  }

  const baseUrl = getBaseUrl(config.provider, config.baseUrl);
  const timeout = config.timeout || DEFAULT_TIMEOUT;

  const controller = new AbortController();
  let abortedByTimeout = false;
  const timeoutId = setTimeout(() => {
    abortedByTimeout = true;
    controller.abort();
  }, timeout);

  const externalSignal = callback.signal;
  const onExternalAbort = () => controller.abort();
  if (externalSignal) {
    if (externalSignal.aborted) {
      clearTimeout(timeoutId);
      callback.onStop?.();
      return;
    }
    externalSignal.addEventListener("abort", onExternalAbort, { once: true });
  }

  let reader: ReadableStreamDefaultReader<Uint8Array> | null = null;

  try {
    callback.onStart?.();

    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify({
        model: config.model,
        messages: [
          { role: "system", content: prompt },
          { role: "user", content },
        ],
        stream: true,
      }),
      signal: controller.signal,
    });

    if (!response.ok) {
      let detail = "";
      try {
        detail = (await response.text()).slice(0, 400);
      } catch {
        // ignore
      }
      throw new Error(
        detail
          ? `AI 接口错误 (${response.status})：${detail}`
          : `AI 接口错误：HTTP ${response.status} ${response.statusText}`,
      );
    }

    reader = response.body?.getReader() ?? null;
    if (!reader) {
      throw new Error("响应体为空，无法读取流式内容");
    }

    const decoder = new TextDecoder();
    let buffer = "";

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() || "";

      for (const line of lines) {
        if (!line.trim() || !line.startsWith("data: ")) continue;
        const data = line.slice(6);
        if (data === "[DONE]") continue;

        try {
          const parsed = JSON.parse(data);
          const messageContent = parsed.choices?.[0]?.delta?.content;
          if (messageContent) {
            callback.onMessage?.({ content: messageContent });
          }
        } catch {
          // Skip invalid JSON
        }
      }
    }

    callback.onStop?.();
  } catch (error) {
    if (error instanceof Error && error.name === "AbortError") {
      if (abortedByTimeout) {
        callback.onError?.(new Error("AI 请求超时，请稍后重试。"));
      } else {
        callback.onStop?.();
      }
    } else {
      callback.onError?.(normalizeAiError(error));
    }
  } finally {
    clearTimeout(timeoutId);
    if (externalSignal) {
      externalSignal.removeEventListener("abort", onExternalAbort);
    }
    if (reader) {
      try {
        await reader.cancel();
      } catch {
        // Ignore cancel errors
      }
    }
  }
}

/**
 * AI API Service
 * Compatible with the original Kortex aiApiService interface
 */
export const aiApiService = {
  /**
   * Continue writing - streaming
   */
  continueWriting(content: string, sysPrompt: string, callback: AiStreamCallback): void {
    const prompt = `${sysPrompt}\n\n你是一个专业的写作助手。请根据用户选中的文字，续写接下来的内容。保持原文的风格和语气。只输出续写的内容，不要重复用户选中的文字。`;
    sendStreamingRequest(prompt, content, callback, "continue");
  },

  /**
   * Polish text - streaming
   */
  polish(content: string, sysPrompt: string, callback: AiStreamCallback): void {
    const prompt = `${sysPrompt}\n\n你是一个专业的文字润色助手。请润色以下文字，使其更加流畅、专业。保持原意，只输出润色后的文字。`;
    sendStreamingRequest(prompt, content, callback, "polish");
  },

  /**
   * Summarize content - streaming
   */
  summarize(content: string, sysPrompt: string, callback: AiStreamCallback): void {
    const prompt = `${sysPrompt}\n\n你是一个专业的总结助手。请总结以下内容的要点。简洁明了，输出总结内容。`;
    sendStreamingRequest(prompt, content, callback, "summarize");
  },

  /**
   * Translate text - streaming
   */
  translate(
    content: string,
    targetLang: string,
    sysPrompt: string,
    callback: AiStreamCallback,
  ): void {
    const prompt = `${sysPrompt}\n\n你是一个专业的翻译助手。请将以下内容翻译为${targetLang}。只输出翻译结果。`;
    sendStreamingRequest(prompt, content, callback, "translate");
  },

  /**
   * Custom AI command - streaming
   */
  customCommand(
    content: string,
    customPrompt: string,
    sysPrompt: string,
    callback: AiStreamCallback,
  ): void {
    const prompt = `${sysPrompt}\n\n${customPrompt}`;
    sendStreamingRequest(prompt, content, callback, "custom");
  },
};

/**
 * Toolbar Config Factories
 * 提供创建工具栏按钮与菜单项的工厂函数
 */
import type { Editor } from "@tiptap/core";

import {
  BoldOutlined,
  ItalicOutlined,
  UnderlineOutlined,
  StrikethroughOutlined,
  CodeOutlined,
  UnorderedListOutlined,
  OrderedListOutlined,
  CheckSquareOutlined,
  EditOutlined,
  ThunderboltOutlined,
  TranslationOutlined,
  FileTextOutlined,
  BulbOutlined,
} from "@ant-design/icons-vue";
import { computed } from "vue";

import { createCommandRunner } from "@/utils/editorCommands";

// import { currentTranslateLang, setTranslateLang } from '../stores/translate'
// 暂时注释掉，后续迁移
const currentTranslateLang = { value: "" };
const setTranslateLang = (_label: string) => {};
import type { ToolbarButtonConfig, HeadingConfig, ListToolConfig, MenuItemConfig } from "./toolbar";

/**
 * 创建文本格式工具配置
 */
export function createTextFormatTools(editor: Editor): ToolbarButtonConfig[] {
  const runCommand = createCommandRunner(computed(() => editor));

  return [
    {
      name: "bold",
      icon: BoldOutlined,
      title: "粗体 (Ctrl+B)",
      action: runCommand((chain) => chain.toggleBold()),
    },
    {
      name: "italic",
      icon: ItalicOutlined,
      title: "斜体 (Ctrl+I)",
      action: runCommand((chain) => chain.toggleItalic()),
    },
    {
      name: "underline",
      icon: UnderlineOutlined,
      title: "下划线 (Ctrl+U)",
      action: runCommand((chain) => (chain as any).toggleUnderline?.() ?? chain),
    },
    {
      name: "strike",
      icon: StrikethroughOutlined,
      title: "删除线",
      action: runCommand((chain) => chain.toggleStrike()),
    },
    {
      name: "code",
      icon: CodeOutlined,
      title: "行内代码",
      action: runCommand((chain) => chain.toggleCode()),
    },
  ];
}

/**
 * 创建标题工具配置
 */
export function createHeadingTools(editor: Editor): HeadingConfig[] {
  const runCommand = createCommandRunner(computed(() => editor));

  const levels = [1, 2, 3, 4, 5, 6] as const;
  return levels.map((level) => ({
    level,
    title: `标题 ${level}`,
    action: runCommand((chain) => chain.toggleHeading({ level })),
  }));
}

/**
 * 创建列表工具配置
 */
export function createListTools(editor: Editor): ListToolConfig[] {
  const runCommand = createCommandRunner(computed(() => editor));

  return [
    {
      name: "bulletList",
      icon: UnorderedListOutlined,
      title: "无序列表",
      action: runCommand((chain) => chain.toggleBulletList()),
    },
    {
      name: "orderedList",
      icon: OrderedListOutlined,
      title: "有序列表",
      action: runCommand((chain) => chain.toggleOrderedList()),
    },
    {
      name: "taskList",
      icon: CheckSquareOutlined,
      title: "任务列表",
      action: runCommand((chain) => (chain as any).toggleTaskList?.() ?? chain),
    },
  ];
}

/**
 * 创建 AI 工具菜单项配置
 * @param editor 编辑器实例
 * @param t 翻译函数，用于国际化
 */
export function createAiToolMenuItems(
  editor: Editor,
  t: (key: string, params?: Record<string, any>) => string = (key) => key,
): MenuItemConfig[] {
  const defaultLang = currentTranslateLang.value || "";

  // 语言代码映射
  const LANGUAGE_CODES = [
    { code: "zh-CN", key: "zh-CN" },
    { code: "zh-TW", key: "zh-TW" },
    { code: "en", key: "en" },
    { code: "ja", key: "ja" },
    { code: "th", key: "th" },
    { code: "fr", key: "fr" },
    { code: "es", key: "es" },
    { code: "pt", key: "pt" },
    { code: "ko", key: "ko" },
    { code: "vi", key: "vi" },
    { code: "ru", key: "ru" },
    { code: "de", key: "de" },
    { code: "hi", key: "hi" },
    { code: "id", key: "id" },
  ];

  return [
    {
      key: "continueWriting",
      label: t("editor.continueWriting"),
      icon: ThunderboltOutlined,
      action: () => {
        editor.commands.focus();
        (editor.commands as any).continueWriting?.();
      },
    },
    {
      key: "polish",
      label: t("editor.polish"),
      icon: EditOutlined,
      action: () => {
        editor.commands.focus();
        (editor.commands as any).polish?.();
      },
    },
    {
      key: "summarize",
      label: t("editor.summarize"),
      icon: FileTextOutlined,
      action: () => {
        editor.commands.focus();
        (editor.commands as any).summarize?.();
      },
    },
    {
      key: "translate",
      label: defaultLang ? t("editor.translateTo", { lang: defaultLang }) : t("editor.translate"),
      icon: TranslationOutlined,
      action: () => {
        requestAnimationFrame(() => {
          requestAnimationFrame(() => {
            editor.commands.focus();
            (editor.commands as any).translate?.(currentTranslateLang.value);
          });
        });
      },
      children: LANGUAGE_CODES.map(({ code, key }) => {
        const langLabel = t(`editor.lang.${key}`);
        return {
          key: `translate-${code}`,
          label: langLabel,
          action: () => {
            setTranslateLang(langLabel);
            requestAnimationFrame(() => {
              requestAnimationFrame(() => {
                editor.commands.focus();
                (editor.commands as any).translate?.(langLabel);
              });
            });
          },
        };
      }),
    },
    {
      key: "customAi",
      label: t("editor.customAi"),
      icon: BulbOutlined,
      action: () => {
        editor.commands.focus();
        (editor.commands as any).customAi?.();
      },
    },
  ];
}

/**
 * Editor Types
 */

import type { Editor } from "@tiptap/vue-3";

/** Editor version/tier */
export type EditorVersion = "basic" | "advanced" | "premium";

/** Feature configuration */
export interface FeatureConfig {
  // Basic features
  heading?: boolean;
  textFormat?: boolean;
  list?: boolean;
  align?: boolean;
  color?: boolean;
  image?: boolean;

  // Advanced features
  font?: boolean;
  link?: boolean;
  table?: boolean;
  codeBlock?: boolean;
  formatPainter?: boolean;
  undoRedo?: boolean;

  // Tools
  headerNav?: boolean;
  footerNav?: boolean;
  floatingMenu?: boolean;
  dragHandleMenu?: boolean;
  tableToolbar?: boolean;
  imageToolbar?: boolean;
  linkBubbleMenu?: boolean;
}

/** Tiptap Editor Props */
export interface TiptapEditorProps {
  /** Initial HTML or JSON content */
  initialContent?: string | Record<string, any>;

  /** Read-only mode */
  readonly?: boolean;

  /** Preview mode (hides toolbars) */
  previewMode?: boolean;

  /** Editor version tier */
  version?: EditorVersion;

  /** Feature toggles */
  features?: FeatureConfig;

  /** Placeholder text */
  placeholder?: string;

  /** Locale */
  locale?: "zh-CN" | "zh-TW" | "en-US";
}

/** Editor exposed methods */
export interface TiptapEditorExpose {
  getEditor: () => Editor | null;
  getJSON: () => Record<string, any> | null;
  getHTML: () => string;
  getText: () => string;
}

/**
 * FormatPainter Extension - 格式刷
 * @description 采样当前选区样式并应用到目标选区
 */
import { Extension } from "@tiptap/core";
import { Plugin } from "@tiptap/pm/state";

import type { Editor } from "@tiptap/core";

// 为自定义命令添加类型声明，以扩展 RawCommands
declare module "@tiptap/core" {
  interface Commands<ReturnType> {
    formatPainter: {
      /**
       * 开启格式刷并采样当前选区样式
       * @param mode - 模式：1 为单次模式（默认），2 为连续模式
       */
      startFormatPainting: (mode?: 1 | 2) => ReturnType;
      /** 开启格式刷连续应用模式 */
      startContinuousFormatPainting: () => ReturnType;
      /** 将采样到的样式应用到当前选区 */
      applyFormat: () => ReturnType;
      /** 取消格式刷状态并清除缓存 */
      cancelFormatPainting: () => ReturnType;
      /** 切换连续应用模式 */
      toggleContinuousMode: () => ReturnType;
    };
  }
}

export interface FormatPainterStorage {
  /** 格式刷是否激活 */
  isActive: boolean;
  /** 是否为连续应用模式 */
  isContinuous: boolean;
  /** 采样的格式 */
  formats: {
    bold?: boolean;
    italic?: boolean;
    underline?: boolean;
    strike?: boolean;
    subscript?: boolean;
    superscript?: boolean;
    color?: string | null;
    highlight?: string | null;
    fontFamily?: string | null;
    fontSize?: string | null;
    textAlign?: "left" | "center" | "right" | "justify" | null;
    lineHeight?: string | null;
  };
}

/** 本地存储的键名 */
const STORAGE_KEY = "tiptap-format-painter-formats";

export type FormatPainterFormats = FormatPainterStorage["formats"];

/**
 * 采样当前选区的格式样式
 * @param editor - Tiptap 编辑器实例
 * @returns 格式对象，如果采样失败则返回 null
 * @description 从编辑器中提取当前选区的所有格式信息，包括文本样式、颜色、对齐等
 */
export function sampleFormats(editor: Editor): FormatPainterFormats | null {
  try {
    const formats: FormatPainterFormats = {};

    // 基础文本样式
    formats.bold = editor.isActive("bold");
    formats.italic = editor.isActive("italic");
    formats.underline = editor.isActive("underline");
    formats.strike = editor.isActive("strike");
    formats.subscript = editor.isActive("subscript");
    formats.superscript = editor.isActive("superscript");

    // 从 textStyle 中获取颜色和字体样式
    const textStyleAttrs = editor.getAttributes("textStyle") as {
      color?: string;
      fontFamily?: string;
      fontSize?: string;
      lineHeight?: string;
    };
    formats.color = textStyleAttrs?.color ?? null;
    formats.fontFamily = textStyleAttrs?.fontFamily ?? null;
    formats.fontSize = textStyleAttrs?.fontSize ?? null;
    formats.lineHeight = textStyleAttrs?.lineHeight ?? null;

    // 从 highlight mark 中获取背景高亮颜色
    const highlightAttrs = editor.getAttributes("highlight") as { color?: string };
    formats.highlight = highlightAttrs?.color ?? null;

    // 对齐（可能存在于段落或标题上）
    const paragraphAttrs = editor.getAttributes("paragraph") as {
      textAlign?: "left" | "center" | "right" | "justify";
    };
    const headingAttrs = editor.getAttributes("heading") as {
      textAlign?: "left" | "center" | "right" | "justify";
    };
    formats.textAlign = paragraphAttrs?.textAlign ?? headingAttrs?.textAlign ?? null;

    return formats;
  } catch (error) {
    return null;
  }
}

/**
 * 保存格式到浏览器本地存储
 * @param formats - 格式对象
 */
function saveFormatsToStorage(formats: FormatPainterFormats): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(formats));
  } catch (error) {
    // ignore
  }
}

/**
 * 从浏览器本地存储加载格式
 * @returns 格式对象，如果不存在则返回 null
 */
function loadFormatsFromStorage(): FormatPainterFormats | null {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) {
      return JSON.parse(data) as FormatPainterFormats;
    }
  } catch (error) {
    // ignore
  }
  return null;
}

/**
 * 清除浏览器本地存储中的格式
 */
function clearFormatsFromStorage(): void {
  try {
    localStorage.removeItem(STORAGE_KEY);
  } catch (error) {
    // ignore
  }
}

/**
 * 更新格式刷光标样式
 * @param editor - Tiptap 编辑器实例
 * @param add - 是否添加样式类，true 为添加，false 为移除
 * @description 添加或移除格式刷光标样式类
 */
function updateCursorStyle(editor: Editor, add: boolean): void {
  try {
    const dom = editor.view.dom;
    if (add) {
      dom.classList.add("cursor-format-painter");
    } else {
      dom.classList.remove("cursor-format-painter");
    }
  } catch (error) {
    // ignore
  }
}

/**
 * 是否处于“多人协作”状态
 * @description
 * - 仅检测到 collaboration 扩展并不代表一定是多人（也可能只是自己在线）
 * - 协作人数由业务层写入 `editor.storage.__collaborationUsersCount`
 * - 仅当人数 > 1 时才认为是多人协作（需要禁用格式刷）
 */
function isCollaborationMultiUser(editor: Editor): boolean {
  try {
    const hasCollaboration = editor.extensionManager.extensions.some(
      (ext) => ext.name === "collaboration",
    );
    if (!hasCollaboration) return false;

    // 业务层注入：TiptapProEditor.vue 会同步此值
    const anyEditor = editor as any;
    const count = Number(anyEditor?.storage?.__collaborationUsersCount ?? 0);
    return count > 1;
  } catch (error) {
    return false;
  }
}

export const FormatPainter = Extension.create<{}, FormatPainterStorage>({
  name: "formatPainter",

  addStorage() {
    // 尝试从本地存储恢复格式
    const savedFormats = loadFormatsFromStorage();
    return {
      isActive: false,
      isContinuous: false,
      formats: savedFormats || {},
    };
  },

  addCommands() {
    return {
      /**
       * 采样当前选区的格式
       * @param mode - 模式：1 为单次模式（默认），2 为连续模式
       * @description 获取选中文本的所有格式信息并保存，根据 mode 决定是单次还是连续应用
       */
      startFormatPainting:
        (mode?: 1 | 2) =>
        ({ editor }) => {
          // 多人协作时禁用格式刷
          if (isCollaborationMultiUser(editor)) {
            return false;
          }

          // 检查是否有选中内容
          try {
            const sel = editor.state.selection;
            if (!sel || sel.empty) {
              return false;
            }
          } catch (error) {
            return false;
          }

          // 采样格式信息
          const formats = sampleFormats(editor);
          if (!formats) {
            return false;
          }

          // 保存格式到内存和本地存储
          this.storage.formats = formats;
          this.storage.isActive = true;
          // 如果传入 2 则为连续模式，否则（1 或 undefined）为单次模式
          this.storage.isContinuous = mode === 2;
          saveFormatsToStorage(formats);

          // 更新光标样式
          updateCursorStyle(editor, true);

          return true;
        },

      /**
       * 采样当前选区的格式（连续应用模式）
       * @description 获取选中文本的所有格式信息并保存，可以连续应用多次
       */
      startContinuousFormatPainting:
        () =>
        ({ editor }) => {
          // 多人协作时禁用格式刷
          if (isCollaborationMultiUser(editor)) {
            return false;
          }

          // 检查是否有选中内容
          try {
            const sel = editor.state.selection;
            if (!sel || sel.empty) {
              return false;
            }
          } catch (error) {
            return false;
          }

          // 采样格式信息
          const formats = sampleFormats(editor);
          if (!formats) {
            return false;
          }

          // 保存格式到内存和本地存储
          this.storage.formats = formats;
          this.storage.isActive = true;
          this.storage.isContinuous = true;
          saveFormatsToStorage(formats);

          // 更新光标样式
          updateCursorStyle(editor, true);

          return true;
        },

      /**
       * 将保存的格式应用到当前选区
       * @description 将之前采样的格式应用到当前选中的文本
       */
      applyFormat:
        () =>
        ({ editor }) => {
          // 多人协作时禁用格式刷
          if (isCollaborationMultiUser(editor)) {
            // 如果格式刷已激活，则取消激活状态
            if (this.storage.isActive) {
              this.storage.isActive = false;
              this.storage.isContinuous = false;
              updateCursorStyle(editor, false);
            }
            return false;
          }

          // 检查格式刷是否已激活
          if (!this.storage.isActive) {
            return false;
          }

          // 检查是否有选中内容
          try {
            const sel = editor.state.selection;
            if (!sel || sel.empty) {
              return false;
            }
          } catch (error) {
            return false;
          }

          // 检查是否有格式信息（优先从内存，其次从本地存储）
          let formats = this.storage.formats;
          if (!formats || Object.keys(formats).length === 0) {
            const savedFormats = loadFormatsFromStorage();
            if (savedFormats) {
              this.storage.formats = savedFormats;
              formats = savedFormats;
            }
          }

          if (!formats || Object.keys(formats).length === 0) {
            return false;
          }

          const { from, to } = editor.state.selection;

          try {
            // 应用文本级格式
            const chain = editor.chain().focus();

            // 处理粗体
            if (formats.bold) chain.setMark("bold");
            else chain.unsetMark("bold");

            // 处理斜体
            if (formats.italic) chain.setMark("italic");
            else chain.unsetMark("italic");

            // 处理下划线
            if (formats.underline) chain.setMark("underline");
            else chain.unsetMark("underline");

            // 处理删除线
            if (formats.strike) chain.setMark("strike");
            else chain.unsetMark("strike");

            // 处理上下标（互斥，先清除再设置）
            chain.unsetMark("subscript").unsetMark("superscript");
            if (formats.subscript) chain.setMark("subscript");
            else if (formats.superscript) chain.setMark("superscript");

            // 构建 textStyle 属性对象
            const textStyleAttrs: any = {};
            if (formats.color) textStyleAttrs.color = formats.color;
            if (formats.fontFamily) textStyleAttrs.fontFamily = formats.fontFamily;
            if (formats.fontSize) textStyleAttrs.fontSize = formats.fontSize;

            // 应用 textStyle（如果有属性）
            if (Object.keys(textStyleAttrs).length > 0) {
              chain.setMark("textStyle", textStyleAttrs);
            } else {
              chain.unsetMark("textStyle");
            }

            // 处理背景高亮
            if (formats.highlight) {
              (chain as any).setHighlight({ color: formats.highlight });
            } else {
              (chain as any).unsetHighlight?.();
            }

            // 执行所有文本级格式
            chain.run();

            // 处理段落级格式（对齐和行距）
            if (formats.textAlign) {
              editor
                .chain()
                .focus()
                .setTextSelection({ from, to })
                .setTextAlign(formats.textAlign)
                .run();
            }

            if (formats.lineHeight) {
              editor
                .chain()
                .focus()
                .setTextSelection({ from, to })
                .setLineHeight(formats.lineHeight)
                .run();
            }
          } catch (error) {
            return false;
          }

          // 如果不是连续模式，应用后关闭格式刷
          if (!this.storage.isContinuous) {
            this.storage.isActive = false;
            updateCursorStyle(editor, false);
          }

          return true;
        },

      /**
       * 取消格式刷状态并清除缓存
       * @description 清除格式刷的激活状态、保存的格式信息以及浏览器缓存
       */
      cancelFormatPainting:
        () =>
        ({ editor }) => {
          this.storage.isActive = false;
          this.storage.isContinuous = false;
          this.storage.formats = {};
          clearFormatsFromStorage();
          updateCursorStyle(editor, false);
          return true;
        },

      /**
       * 切换连续应用模式
       * @description 切换格式刷的连续应用模式开关
       */
      toggleContinuousMode: () => () => {
        this.storage.isContinuous = !this.storage.isContinuous;
        return true;
      },
    };
  },

  addProseMirrorPlugins() {
    const ext = this;
    return [
      new Plugin({
        props: {
          // 监听键盘事件，ESC 键退出格式刷
          handleKeyDown(_view, event: KeyboardEvent) {
            const storage = ext.storage;
            if (storage.isActive && event.key === "Escape") {
              ext.editor?.commands.cancelFormatPainting();
              return true; // 阻止默认行为
            }
            return false;
          },

          // 监听鼠标抬起事件，在格式刷激活时自动应用格式
          handleDOMEvents: {
            mouseup: () => {
              const storage = ext.storage;
              if (storage.isActive && ext.editor) {
                // 使用 requestAnimationFrame 代替 setTimeout，确保在下一帧执行
                requestAnimationFrame(() => {
                  // 再次检查格式刷是否仍然激活（可能在延迟期间被取消）
                  if (!storage.isActive || !ext.editor) {
                    return;
                  }

                  try {
                    // 获取当前最新的选区状态
                    const { state } = ext.editor;
                    const { empty } = state.selection;

                    // 如果有选区，自动应用格式
                    if (!empty) {
                      ext.editor.commands.applyFormat();
                    }
                  } catch (error) {
                    // ignore
                  }
                });
              }
              return false;
            },
          },
        },
      }),
    ];
  },
});

